files.content:
@layer cascivo.component {
  .root {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-8);
    padding-block: var(--cascivo-space-12);
  }

  .header {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
    text-align: center;
  }

  .heading {
    margin: 0;
    font-family: var(--cascivo-font-display);
    font-size: var(--cascivo-text-3xl);
    font-weight: var(--cascivo-font-bold);
    color: var(--cascivo-color-text);
  }

  .subtitle {
    margin: 0;
    color: var(--cascivo-color-text-muted);
  }

  .grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(15rem, 1fr));
    gap: var(--cascivo-space-6);
    align-items: start;
  }

  .card {
    display: flex;
    flex-direction: column;
    height: 100%;
  }

  .card[data-featured] {
    border-color: var(--cascivo-color-accent);
  }

  .tierName {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--cascivo-space-2);
  }

  .price {
    margin: var(--cascivo-space-2) 0 0;
    display: flex;
    align-items: baseline;
    gap: var(--cascivo-space-1);
  }

  .amount {
    font-size: var(--cascivo-text-3xl);
    font-weight: var(--cascivo-font-bold);
    color: var(--cascivo-color-text);
  }

  .period {
    color: var(--cascivo-color-text-muted);
    font-size: var(--cascivo-text-sm);
  }

  .tierDescription {
    margin: var(--cascivo-space-2) 0 0;
    color: var(--cascivo-color-text-muted);
    font-size: var(--cascivo-text-sm);
  }

  .features {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
    margin: 0;
    padding: 0;
    list-style: none;
  }

  .feature {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    color: var(--cascivo-color-text);
    font-size: var(--cascivo-text-sm);
  }

  .check {
    color: var(--cascivo-color-success);
    font-weight: var(--cascivo-font-bold);
  }

  .cta {
    inline-size: 100%;
  }
}
